import re
from flask import Flask, request, Response
from prometheus_client import Counter, CollectorRegistry, generate_latest, CONTENT_TYPE_LATEST

app = Flask(__name__)
registry = CollectorRegistry()
counters = {}


def sanitize(name: str) -> str:
    return re.sub(r'[^a-zA-Z0-9_]', '_', name)


def get_counter(user_id: str, path: str) -> Counter:
    key = (user_id, path)
    if key not in counters:
        metric_name = f"http_requests_total_{sanitize(user_id)}_{sanitize(path)}"
        counters[key] = Counter(
            metric_name,
            f"HTTP requests for user '{user_id}' and path '{path}'",
            ["session_id", "full_path"],
            registry=registry,
        )
    return counters[key]


@app.before_request
def track_http_request():
    user_id = request.headers.get("X-User-Id", "anonymous")
    session_id = request.headers.get("X-Session-Id", "unknown")
    full_path = request.full_path or request.path
    counter = get_counter(user_id, request.path)
    counter.labels(session_id=session_id, full_path=full_path).inc()


@app.route("/metrics")
def metrics():
    return Response(generate_latest(registry), mimetype=CONTENT_TYPE_LATEST)


